### **PASSO CRÍTICO: Atualizar o Código PHP no WordPress**

Você precisa substituir o código no arquivo `monitor-app.php` (na pasta `mu-plugins` ou `functions.php`) em **todos os sites**.

Esta versão adiciona as linhas de permissão (CORS) e garante que não dê erro se o Koko Analytics estiver vazio (recém instalado).

```php
<?php
/*
Plugin Name: Monitor App API
Description: API para aplicativo de monitoramento (Forms + Koko Analytics) com suporte a CORS.
Version: 1.2
Author: Dev
*/

// Configure sua chave secreta igual à do App
$api_key_secret = '157918';

// Função auxiliar para permitir acesso externo (CORS)
function monitor_allow_cors() {
    header("Access-Control-Allow-Origin: *");
    header("Access-Control-Allow-Methods: GET, OPTIONS");
    header("Access-Control-Allow-Headers: Content-Type");
}

// Endpoint de Forms (Elementor)
add_action('rest_api_init', function () use ($api_key_secret) {
    register_rest_route('monitor-app/v1', '/submissions', array(
        'methods' => 'GET',
        'callback' => function ($request) use ($api_key_secret) {
            monitor_allow_cors(); // Permite acesso externo

            $key = $request->get_param('key');
            if ($key !== $api_key_secret) {
                return new WP_Error('forbidden', 'Chave inválida', array('status' => 403));
            }

            global $wpdb;
            // Tenta tabela do Elementor Pro
            $table_name = $wpdb->prefix . 'e_submissions';

            // Verifica se a tabela existe
            if ($wpdb->get_var("SHOW TABLES LIKE '$table_name'") != $table_name) {
                 return array('success' => true, 'data' => []);
            }

            $results = $wpdb->get_results("
                SELECT s.id, s.created_at as date,
                MAX(CASE WHEN v.key = 'name' OR v.key LIKE '%nome%' THEN v.value END) as name,
                MAX(CASE WHEN v.key = 'email' THEN v.value END) as email,
                MAX(CASE WHEN v.key = 'message' OR v.key LIKE '%mensagem%' THEN v.value END) as message
                FROM {$wpdb->prefix}e_submissions s
                LEFT JOIN {$wpdb->prefix}e_submissions_values v ON s.id = v.submission_id
                GROUP BY s.id
                ORDER BY s.created_at DESC
                LIMIT 20
            ");

            return array('success' => true, 'data' => $results);
        },
        'permission_callback' => '__return_true',
    ));
});

// Endpoint de Estatísticas (Koko Analytics)
add_action('rest_api_init', function () use ($api_key_secret) {
    register_rest_route('monitor-app/v1', '/stats', array(
        'methods' => 'GET',
        'callback' => function ($request) use ($api_key_secret) {
            monitor_allow_cors(); // Permite acesso externo

            $key = $request->get_param('key');
            if ($key !== $api_key_secret) {
                return new WP_Error('forbidden', 'Chave inválida', array('status' => 403));
            }

            global $wpdb;
            $table_name = $wpdb->prefix . 'koko_analytics_site_stats';

            $monthly_visitors = 0;
            $daily_visitors = 0;
            $online_estimate = 0;

            // Verifica se tabela do Koko existe
            if ($wpdb->get_var("SHOW TABLES LIKE '$table_name'") == $table_name) {
                $current_month = date('Y-m-'); 
                $today = date('Y-m-d');

                // 1. Visitantes do Mês
                $monthly_visitors = (int) $wpdb->get_var(
                    $wpdb->prepare(
                        "SELECT SUM(visitors) FROM $table_name WHERE date LIKE %s",
                        $current_month . '%'
                    )
                );

                // 2. Visitantes de Hoje (para estimar online)
                $daily_visitors = (int) $wpdb->get_var(
                    $wpdb->prepare(
                        "SELECT visitors FROM $table_name WHERE date = %s",
                        $today
                    )
                );

                // Estimativa simples: Tráfego do dia / 50 (ajuste conforme preferir)
                if ($daily_visitors > 0) {
                    $online_estimate = max(1, round($daily_visitors / 50));
                }
            }

            // DEBUG: Se quiser testar se está funcionando mesmo sem tráfego, descomente a linha abaixo:
            // $monthly_visitors = 1234; $online_estimate = 5;

            return array(
                'success' => true, 
                'data' => array(
                    'online_users' => $online_estimate,
                    'monthly_visitors' => $monthly_visitors
                )
            );
        },
        'permission_callback' => '__return_true',
    ));
});

